using ContosoUniversity.Data;
using Microsoft.EntityFrameworkCore;
using System;

namespace ContosoUniversity.Tests
{
    public static class TestDbContextFactory
    {
        public static SchoolContext Create(string dbName = null)
        {
            dbName ??= Guid.NewGuid().ToString();
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: dbName)
                .Options;
            var context = new SchoolContext(options);
            context.Database.EnsureCreated();
            return context;
        }
    }
}

using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly StudentsController _controller;

        public StudentsControllerTests()
        {
            _context = TestDbContextFactory.Create();
            SeedStudents();
            _controller = new StudentsController(_context);
        }

        private void SeedStudents()
        {
            _context.Students.AddRange(
                new Student { LastName = "Alexander", FirstMidName = "Carson", EnrollmentDate = DateTime.Parse("2019-09-01") },
                new Student { LastName = "Alonso", FirstMidName = "Meredith", EnrollmentDate = DateTime.Parse("2017-09-01") },
                new Student { LastName = "Anand", FirstMidName = "Arturo", EnrollmentDate = DateTime.Parse("2018-09-01") },
                new Student { LastName = "Barzdukas", FirstMidName = "Gytis", EnrollmentDate = DateTime.Parse("2017-09-01") }
            );
            _context.SaveChanges();
        }

        [Fact]
        public void Index_ReturnsViewResult_WithPaginatedList()
        {
            var result = _controller.Index(null, null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal(4, model.Count);
        }

        [Fact]
        public void Index_SortsByNameDescending()
        {
            var result = _controller.Index("name_desc", null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal("Barzdukas", model.First().LastName);
        }

        [Fact]
        public void Index_SortsByDateAscending()
        {
            var result = _controller.Index("Date", null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            // 2017 dates should come first
            Assert.Equal(2017, model.First().EnrollmentDate.Year);
        }

        [Fact]
        public void Index_SortsByDateDescending()
        {
            var result = _controller.Index("date_desc", null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal(2019, model.First().EnrollmentDate.Year);
        }

        [Fact]
        public void Index_FiltersStudents_BySearchString()
        {
            var result = _controller.Index(null, null, "Alexander", null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Single(model);
            Assert.Equal("Alexander", model.First().LastName);
        }

        [Fact]
        public void Index_FiltersStudents_ByFirstName()
        {
            var result = _controller.Index(null, null, "Carson", null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Single(model);
        }

        [Fact]
        public void Index_UsesCurrentFilter_WhenSearchStringIsNull()
        {
            var result = _controller.Index(null, "Alexander", null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Single(model);
        }

        [Fact]
        public void Index_ResetsPage_WhenSearchStringProvided()
        {
            var result = _controller.Index(null, null, "Alexander", 2);

            var viewResult = Assert.IsType<ViewResult>(result);
            // Page resets to 1 when new search is provided
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal(1, model.PageIndex);
        }

        [Fact]
        public void Details_ReturnsNotFound_WhenIdIsNull()
        {
            var result = _controller.Details(null);

            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Details_ReturnsViewResult_WithStudent()
        {
            var student = _context.Students.First();

            var result = _controller.Details(student.ID);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Student>(viewResult.Model);
            Assert.Equal(student.ID, model.ID);
        }

        [Fact]
        public void Create_Get_ReturnsViewResult_WithDefaultDate()
        {
            var result = _controller.Create();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Student>(viewResult.Model);
            Assert.Equal(DateTime.Today, model.EnrollmentDate);
        }

        [Fact]
        public void Create_Post_RedirectsToIndex_WhenModelIsValid()
        {
            var student = new Student
            {
                LastName = "TestLast",
                FirstMidName = "TestFirst",
                EnrollmentDate = DateTime.Parse("2020-09-01")
            };

            var result = _controller.Create(student);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
            Assert.Equal(5, _context.Students.Count());
        }

        [Fact]
        public void Create_Post_ReturnsView_WhenEnrollmentDateIsMinValue()
        {
            var student = new Student
            {
                LastName = "TestLast",
                FirstMidName = "TestFirst",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Create(student);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        [Fact]
        public void Create_Post_ReturnsView_WhenEnrollmentDateOutOfRange()
        {
            var student = new Student
            {
                LastName = "TestLast",
                FirstMidName = "TestFirst",
                EnrollmentDate = new DateTime(1600, 1, 1)
            };

            var result = _controller.Create(student);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        [Fact]
        public void Create_Post_ReturnsView_WhenModelStateInvalid()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                FirstMidName = "TestFirst",
                EnrollmentDate = DateTime.Parse("2020-09-01")
            };

