    public class PaginatedListTests
    {
        [Fact]
        public void Create_ReturnsCorrectPage()
        {
            var items = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(items, 1, 10);

            Assert.Equal(10, result.Count);
            Assert.Equal(1, result.First());
            Assert.Equal(10, result.Last());
        }

        [Fact]
        public void Create_SecondPage_ReturnsCorrectItems()
        {
            var items = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(items, 2, 10);

            Assert.Equal(10, result.Count);
            Assert.Equal(11, result.First());
            Assert.Equal(20, result.Last());
        }

        [Fact]
        public void Create_LastPage_ReturnsRemainingItems()
        {
            var items = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(items, 3, 10);

            Assert.Equal(5, result.Count);
            Assert.Equal(21, result.First());
            Assert.Equal(25, result.Last());
        }

        [Fact]
        public void TotalPages_CalculatedCorrectly()
        {
            var items = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(items, 1, 10);

            Assert.Equal(3, result.TotalPages);
        }

        [Fact]
        public void TotalPages_SinglePage()
        {
            var items = Enumerable.Range(1, 5).AsQueryable();

            var result = PaginatedList<int>.Create(items, 1, 10);

            Assert.Equal(1, result.TotalPages);
        }

        [Fact]
        public void HasPreviousPage_FalseForFirstPage()
        {
            var items = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(items, 1, 10);

            Assert.False(result.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_TrueForSecondPage()
        {
            var items = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(items, 2, 10);

            Assert.True(result.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_TrueForFirstPage()
        {
            var items = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(items, 1, 10);

            Assert.True(result.HasNextPage);
        }

        [Fact]
        public void HasNextPage_FalseForLastPage()
        {
            var items = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(items, 3, 10);

            Assert.False(result.HasNextPage);
        }

        [Fact]
        public void PageIndex_SetCorrectly()
        {
            var items = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(items, 2, 10);

            Assert.Equal(2, result.PageIndex);
        }

        [Fact]
        public void Constructor_SetsProperties()
        {
            var list = new List<string> { "a", "b", "c" };

            var paginated = new PaginatedList<string>(list, 10, 2, 5);

            Assert.Equal(3, paginated.Count);
            Assert.Equal(2, paginated.PageIndex);
            Assert.Equal(2, paginated.TotalPages);
        }

