        {
            var initialCount = _context.Courses.Count();

            var result = _controller.DeleteConfirmed(1050);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            Assert.Equal(initialCount - 1, _context.Courses.Count());
        }

        private Mock<IFormFile> CreateMockFile(string fileName, long length)
        {
            var mock = new Mock<IFormFile>();
            mock.Setup(f => f.FileName).Returns(fileName);
            mock.Setup(f => f.Length).Returns(length);
            var ms = new MemoryStream(new byte[Math.Min((int)length, 1024)]);
            mock.Setup(f => f.CopyTo(It.IsAny<Stream>())).Callback<Stream>(s => ms.CopyTo(s));
            return mock;
        }

        public void Dispose()
        {
            _controller?.Dispose();
            _context?.Dispose();
            if (Directory.Exists(_tempDir))
            {
                try { Directory.Delete(_tempDir, true); } catch { }
            }
        }
    }
}

