using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using Moq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class CoursesControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly CoursesController _controller;
        private readonly Mock<IWebHostEnvironment> _mockEnv;
        private readonly Mock<ILogger<CoursesController>> _mockLogger;
        private readonly string _tempDir;

        public CoursesControllerTests()
        {
            _context = TestDbContextFactory.Create();
            _tempDir = Path.Combine(Path.GetTempPath(), Guid.NewGuid().ToString());
            Directory.CreateDirectory(_tempDir);

            _mockEnv = new Mock<IWebHostEnvironment>();
            _mockEnv.Setup(e => e.WebRootPath).Returns(_tempDir);
            _mockEnv.Setup(e => e.ContentRootPath).Returns(_tempDir);

            _mockLogger = new Mock<ILogger<CoursesController>>();

            SeedData();
            _controller = new CoursesController(_context, _mockEnv.Object, _mockLogger.Object);
        }

        private void SeedData()
        {
            var dept = new Department { DepartmentID = 1, Name = "Engineering", Budget = 100000, StartDate = DateTime.Parse("2007-09-01") };
            _context.Departments.Add(dept);

            _context.Courses.AddRange(
                new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 },
                new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = 1 },
                new Course { CourseID = 4041, Title = "Macroeconomics", Credits = 3, DepartmentID = 1 }
            );
            _context.SaveChanges();
        }

        [Fact]
        public void Index_ReturnsViewResult_WithListOfCourses()
        {
            var result = _controller.Index();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<List<Course>>(viewResult.Model);
            Assert.Equal(3, model.Count);
        }

        [Fact]
        public void Details_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Details(null);

            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Details_ReturnsViewResult_WithCourse()
        {
            var result = _controller.Details(1050);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Course>(viewResult.Model);
            Assert.Equal("Chemistry", model.Title);
        }

        [Fact]
        public void Create_Get_ReturnsViewResult()
        {
            var result = _controller.Create();

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.IsType<Course>(viewResult.Model);
        }

        [Fact]
        public void Create_Post_RedirectsToIndex_WhenValid()
        {
            var course = new Course { CourseID = 2021, Title = "Physics", Credits = 4, DepartmentID = 1 };

            var result = _controller.Create(course, null);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            Assert.NotNull(_context.Courses.Find(2021));
        }

        [Fact]
        public void Create_Post_ReturnsView_WhenModelStateInvalid()
        {
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 2022, Credits = 4, DepartmentID = 1 };

            var result = _controller.Create(course, null);

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Create_Post_RejectsInvalidFileExtension()
        {
            var course = new Course { CourseID = 2023, Title = "Art", Credits = 3, DepartmentID = 1 };
            var mockFile = CreateMockFile("test.exe", 1024);

            var result = _controller.Create(course, mockFile.Object);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Create_Post_RejectsFileTooLarge()
        {
            var course = new Course { CourseID = 2024, Title = "Music", Credits = 3, DepartmentID = 1 };
            var mockFile = CreateMockFile("test.jpg", 6 * 1024 * 1024);

            var result = _controller.Create(course, mockFile.Object);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Create_Post_AcceptsValidImage()
        {
            var course = new Course { CourseID = 2025, Title = "Design", Credits = 3, DepartmentID = 1 };
            var mockFile = CreateMockFile("test.png", 1024);

            var result = _controller.Create(course, mockFile.Object);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            var saved = _context.Courses.Find(2025);
            Assert.NotNull(saved.TeachingMaterialImagePath);
        }

        [Fact]
        public void Edit_Get_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Edit((int?)null);

            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Edit_Get_ReturnsNotFound_WhenCourseNotFound()
        {
            var result = _controller.Edit(9999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Get_ReturnsViewResult_WithCourse()
        {
            var result = _controller.Edit(1050);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Course>(viewResult.Model);
            Assert.Equal("Chemistry", model.Title);
        }

        [Fact]
        public void Edit_Post_RedirectsToIndex_WhenValid()
        {
            var course = _context.Courses.Find(1050);
            _context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var editedCourse = new Course { CourseID = 1050, Title = "Advanced Chemistry", Credits = 4, DepartmentID = 1 };

            var result = _controller.Edit(editedCourse, null);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Edit_Post_RejectsInvalidFileExtension()
        {
            var course = _context.Courses.Find(1050);
            _context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var editedCourse = new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 };
            var mockFile = CreateMockFile("bad.txt", 1024);

            var result = _controller.Edit(editedCourse, mockFile.Object);

            Assert.IsType<ViewResult>(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Delete_Get_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Delete(null);

            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Delete_Get_ReturnsViewResult_WithCourse()
        {
            var result = _controller.Delete(1050);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Course>(viewResult.Model);
            Assert.Equal("Chemistry", model.Title);
        }

        [Fact]
        public void DeleteConfirmed_RemovesCourse_AndRedirects()
        {
            var initialCount = _context.Courses.Count();

            var result = _controller.DeleteConfirmed(1050);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            Assert.Equal(initialCount - 1, _context.Courses.Count());
        }

        private Mock<IFormFile> CreateMockFile(string fileName, long length)
        {
            var mock = new Mock<IFormFile>();
            mock.Setup(f => f.FileName).Returns(fileName);
            mock.Setup(f => f.Length).Returns(length);
            var ms = new MemoryStream(new byte[Math.Min((int)length, 1024)]);
            mock.Setup(f => f.CopyTo(It.IsAny<Stream>())).Callback<Stream>(s => ms.CopyTo(s));
            return mock;
        }

        public void Dispose()
        {
            _controller?.Dispose();
            _context?.Dispose();
            if (Directory.Exists(_tempDir))
            {
                try { Directory.Delete(_tempDir, true); } catch { }
            }
        }
    }
}

