using System;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class DepartmentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly DepartmentsController _controller;

        public DepartmentsControllerTests()
        {
            _context = TestDbContextFactory.Create();
            SeedData();
            _controller = new DepartmentsController(_context);
        }

        private void SeedData()
        {
            var instructor = new Instructor
            {
                LastName = "Kapoor",
                FirstMidName = "Candace",
                HireDate = DateTime.Parse("2001-01-15")
            };
            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            _context.Departments.AddRange(
                new Department { DepartmentID = 1, Name = "English", Budget = 350000, StartDate = DateTime.Parse("2007-09-01"), InstructorID = instructor.ID },
                new Department { DepartmentID = 2, Name = "Mathematics", Budget = 100000, StartDate = DateTime.Parse("2007-09-01") },
                new Department { DepartmentID = 3, Name = "Engineering", Budget = 500000, StartDate = DateTime.Parse("2007-09-01") }
            );
            _context.SaveChanges();
        }

        [Fact]
        public void Index_ReturnsViewResult_WithDepartments()
        {
            var result = _controller.Index();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<Department>>(viewResult.Model);
            Assert.Equal(3, model.Count);
        }

        [Fact]
        public void Details_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Details(null);

            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Details_ReturnsNotFound_WhenDepartmentNotFound()
        {
            var result = _controller.Details(9999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Details_ReturnsViewResult_WithDepartment()
        {
            var result = _controller.Details(1);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Department>(viewResult.Model);
            Assert.Equal("English", model.Name);
        }

        [Fact]
        public void Create_Get_ReturnsViewResult()
        {
            var result = _controller.Create();

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Create_Post_RedirectsToIndex_WhenValid()
        {
            var department = new Department
            {
                Name = "Physics",
                Budget = 200000,
                StartDate = DateTime.Parse("2020-09-01")
            };

            var result = _controller.Create(department);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            Assert.Equal(4, _context.Departments.Count());
        }

        [Fact]
        public void Create_Post_ReturnsView_WhenModelStateInvalid()
        {
            _controller.ModelState.AddModelError("Name", "Required");
            var department = new Department { Budget = 100000, StartDate = DateTime.Now };

            var result = _controller.Create(department);

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Edit_Get_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Edit((int?)null);

            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Edit_Get_ReturnsNotFound_WhenDepartmentNotFound()
        {
            var result = _controller.Edit(9999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Get_ReturnsViewResult_WithDepartment()
        {
            var result = _controller.Edit(1);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Department>(viewResult.Model);
            Assert.Equal("English", model.Name);
        }

        [Fact]
        public void Edit_Post_RedirectsToIndex_WhenValid()
        {
            var dept = _context.Departments.Find(1);
            _context.Entry(dept).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var editedDept = new Department
            {
                DepartmentID = 1,
                Name = "Updated English",
                Budget = 400000,
                StartDate = DateTime.Parse("2007-09-01"),
                InstructorID = dept.InstructorID
            };

            var result = _controller.Edit(editedDept);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Edit_Post_ReturnsView_WhenModelStateInvalid()
        {
            _controller.ModelState.AddModelError("Name", "Required");
            var department = new Department { DepartmentID = 1, Budget = 100000, StartDate = DateTime.Now };

            var result = _controller.Edit(department);

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Delete_Get_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Delete(null);

            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Delete_Get_ReturnsNotFound_WhenDepartmentNotFound()
        {
            var result = _controller.Delete(9999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_Get_ReturnsViewResult_WithDepartment()
        {
            var result = _controller.Delete(1);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Department>(viewResult.Model);
            Assert.Equal("English", model.Name);
        }

        [Fact]
        public void DeleteConfirmed_RemovesDepartment_AndRedirects()
        {
            var initialCount = _context.Departments.Count();

            var result = _controller.DeleteConfirmed(1);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            Assert.Equal(initialCount - 1, _context.Departments.Count());
        }

        public void Dispose()
        {
            _controller?.Dispose();
            _context?.Dispose();
        }
    }
}

