using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class InstructorsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly InstructorsController _controller;

        public InstructorsControllerTests()
        {
            _context = TestDbContextFactory.Create();
            SeedData();
            _controller = new InstructorsController(_context);
        }

        private void SeedData()
        {
            var dept = new Department { DepartmentID = 1, Name = "Engineering", Budget = 350000, StartDate = DateTime.Parse("2007-09-01") };
            _context.Departments.Add(dept);

            var course1 = new Course { CourseID = 1045, Title = "Chemistry", Credits = 3, DepartmentID = 1 };
            var course2 = new Course { CourseID = 2021, Title = "Composition", Credits = 3, DepartmentID = 1 };
            _context.Courses.AddRange(course1, course2);

            var instructor1 = new Instructor
            {
                LastName = "Abercrombie",
                FirstMidName = "Kim",
                HireDate = DateTime.Parse("1995-03-11"),
                CourseAssignments = new List<CourseAssignment>(),
                OfficeAssignment = new OfficeAssignment { Location = "Smith 17" }
            };
            var instructor2 = new Instructor
            {
                LastName = "Fakhouri",
                FirstMidName = "Fadi",
                HireDate = DateTime.Parse("2002-07-06"),
                CourseAssignments = new List<CourseAssignment>()
            };
            _context.Instructors.AddRange(instructor1, instructor2);
            _context.SaveChanges();

            _context.CourseAssignments.Add(new CourseAssignment { InstructorID = instructor1.ID, CourseID = 1045 });
            _context.SaveChanges();
        }

        [Fact]
        public void Index_ReturnsViewResult_WithInstructorIndexData()
        {
            var result = _controller.Index(null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Models.SchoolViewModels.InstructorIndexData>(viewResult.Model);
            Assert.Equal(2, model.Instructors.Count());
        }

        [Fact]
        public void Index_WithInstructorId_ShowsCourses()
        {
            var instructor = _context.Instructors.First(i => i.LastName == "Abercrombie");

            var result = _controller.Index(instructor.ID, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Models.SchoolViewModels.InstructorIndexData>(viewResult.Model);
            Assert.NotNull(model.Courses);
            Assert.Single(model.Courses);
        }

        [Fact]
        public void Details_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Details(null);

            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Details_ReturnsNotFound_WhenInstructorNotFound()
        {
            var result = _controller.Details(9999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Details_ReturnsViewResult_WithInstructor()
        {
            var instructor = _context.Instructors.First();

            var result = _controller.Details(instructor.ID);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Instructor>(viewResult.Model);
            Assert.Equal(instructor.ID, model.ID);
        }

        [Fact]
        public void Create_Get_ReturnsViewResult_WithInstructor()
        {
            var result = _controller.Create();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Instructor>(viewResult.Model);
            Assert.NotNull(model.CourseAssignments);
        }

        [Fact]
        public void Create_Post_RedirectsToIndex_WhenValid()
        {
            var instructor = new Instructor
            {
                LastName = "NewInstructor",
                FirstMidName = "Test",
                HireDate = DateTime.Parse("2020-01-15"),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _controller.Create(instructor, null);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Create_Post_WithSelectedCourses_CreatesCourseAssignments()
        {
            var instructor = new Instructor
            {
                LastName = "CourseInstructor",
                FirstMidName = "With",
                HireDate = DateTime.Parse("2020-01-15"),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _controller.Create(instructor, new[] { "1045", "2021" });

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            var saved = _context.Instructors.First(i => i.LastName == "CourseInstructor");
            var assignments = _context.CourseAssignments.Where(ca => ca.InstructorID == saved.ID).ToList();
            Assert.Equal(2, assignments.Count);
        }

        [Fact]
        public void Create_Post_ReturnsView_WhenModelStateInvalid()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor
            {
                FirstMidName = "Test",
                HireDate = DateTime.Parse("2020-01-15"),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _controller.Create(instructor, null);

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Edit_Get_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Edit((int?)null);

            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Edit_Get_ReturnsViewResult_WithInstructor()
        {
            var instructor = _context.Instructors.First();

            var result = _controller.Edit(instructor.ID);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.IsType<Instructor>(viewResult.Model);
        }

        [Fact]
        public void Delete_Get_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Delete(null);

            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Delete_Get_ReturnsNotFound_WhenInstructorNotFound()
        {
            var result = _controller.Delete(9999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_Get_ReturnsViewResult_WithInstructor()
        {
            var instructor = _context.Instructors.First();

            var result = _controller.Delete(instructor.ID);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Instructor>(viewResult.Model);
            Assert.Equal(instructor.ID, model.ID);
        }

        [Fact]
        public void DeleteConfirmed_RemovesInstructor_AndRedirects()
        {
            var instructor = _context.Instructors.First(i => i.LastName == "Fakhouri");

            var result = _controller.DeleteConfirmed(instructor.ID);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            Assert.Null(_context.Instructors.Find(instructor.ID));
        }

        [Fact]
        public void DeleteConfirmed_NullsDepartmentAdministrator()
        {
            var instructor = _context.Instructors.First(i => i.LastName == "Abercrombie");
            var dept = _context.Departments.First();
            dept.InstructorID = instructor.ID;
            _context.SaveChanges();

            _controller.DeleteConfirmed(instructor.ID);

            var updatedDept = _context.Departments.First(d => d.DepartmentID == dept.DepartmentID);
            Assert.Null(updatedDept.InstructorID);
        }

        public void Dispose()
        {
            _controller?.Dispose();
            _context?.Dispose();
        }
    }
}

