using System;
using System.Linq;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using Xunit;

namespace ContosoUniversity.Tests.Data
{
    public class SchoolContextTests : IDisposable
    {
        private readonly SchoolContext _context;

        public SchoolContextTests()
        {
            _context = TestDbContextFactory.Create();
        }

        [Fact]
        public void CanAddAndRetrieveStudent()
        {
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "Student",
                EnrollmentDate = DateTime.Parse("2020-09-01")
            };

            _context.Students.Add(student);
            _context.SaveChanges();

            var retrieved = _context.Students.First(s => s.LastName == "Test");
            Assert.Equal("Student", retrieved.FirstMidName);
            Assert.Equal(DateTime.Parse("2020-09-01"), retrieved.EnrollmentDate);
        }

        [Fact]
        public void CanAddAndRetrieveInstructor()
        {
            var instructor = new Instructor
            {
                LastName = "Smith",
                FirstMidName = "John",
                HireDate = DateTime.Parse("2015-01-01")
            };

            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            var retrieved = _context.Instructors.First(i => i.LastName == "Smith");
            Assert.Equal("John", retrieved.FirstMidName);
        }

        [Fact]
        public void CanAddCourseWithDepartment()
        {
            var dept = new Department
            {
                Name = "Science",
                Budget = 200000,
                StartDate = DateTime.Parse("2007-09-01")
            };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var course = new Course
            {
                CourseID = 3000,
                Title = "Biology",
                Credits = 4,
                DepartmentID = dept.DepartmentID
            };
            _context.Courses.Add(course);
            _context.SaveChanges();

            var retrieved = _context.Courses.Include(c => c.Department).First(c => c.CourseID == 3000);
            Assert.Equal("Biology", retrieved.Title);
            Assert.Equal("Science", retrieved.Department.Name);
        }

        [Fact]
        public void CanAddEnrollment()
        {
            var student = new Student { LastName = "Enroll", FirstMidName = "Test", EnrollmentDate = DateTime.Now };
            _context.Students.Add(student);
            var dept = new Department { Name = "Dept", Budget = 100000, StartDate = DateTime.Now };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var course = new Course { CourseID = 4000, Title = "TestCourse", Credits = 3, DepartmentID = dept.DepartmentID };
            _context.Courses.Add(course);
            _context.SaveChanges();

            var enrollment = new Enrollment { StudentID = student.ID, CourseID = course.CourseID, Grade = Grade.A };
            _context.Enrollments.Add(enrollment);
            _context.SaveChanges();

            var retrieved = _context.Enrollments.First(e => e.StudentID == student.ID);
            Assert.Equal(Grade.A, retrieved.Grade);
            Assert.Equal(course.CourseID, retrieved.CourseID);
        }

        [Fact]
        public void CourseAssignment_HasCompositeKey()
        {
            var instructor = new Instructor { LastName = "Key", FirstMidName = "Test", HireDate = DateTime.Now };
            _context.Instructors.Add(instructor);
            var dept = new Department { Name = "KeyDept", Budget = 50000, StartDate = DateTime.Now };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var course = new Course { CourseID = 5000, Title = "KeyCourse", Credits = 3, DepartmentID = dept.DepartmentID };
            _context.Courses.Add(course);
            _context.SaveChanges();

            var assignment = new CourseAssignment { InstructorID = instructor.ID, CourseID = course.CourseID };
            _context.CourseAssignments.Add(assignment);
            _context.SaveChanges();

            var retrieved = _context.CourseAssignments.Find(course.CourseID, instructor.ID);
            Assert.NotNull(retrieved);
        }

        [Fact]
        public void OfficeAssignment_OneToOneWithInstructor()
        {
            var instructor = new Instructor
            {
                LastName = "Office",
                FirstMidName = "Test",
                HireDate = DateTime.Now,
                OfficeAssignment = new OfficeAssignment { Location = "Room 101" }
            };
            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            var retrieved = _context.Instructors
                .Include(i => i.OfficeAssignment)
                .First(i => i.LastName == "Office");
            Assert.NotNull(retrieved.OfficeAssignment);
            Assert.Equal("Room 101", retrieved.OfficeAssignment.Location);
        }

        [Fact]
        public void Person_FullName_ConcatenatesLastAndFirst()
        {
            var student = new Student { LastName = "Doe", FirstMidName = "Jane", EnrollmentDate = DateTime.Now };
            Assert.Equal("Doe, Jane", student.FullName);
        }

        [Fact]
        public void Department_CanHaveNullInstructor()
        {
            var dept = new Department
            {
                Name = "NoAdmin",
                Budget = 100000,
                StartDate = DateTime.Parse("2020-01-01"),
                InstructorID = null
            };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var retrieved = _context.Departments.First(d => d.Name == "NoAdmin");
            Assert.Null(retrieved.InstructorID);
        }

        [Fact]
        public void CanAddNotification()
        {
            var notification = new Notification
            {
                EntityType = "Student",
                EntityId = "1",
                Operation = "CREATE",
                Message = "Test notification",
                CreatedAt = DateTime.Now,
                CreatedBy = "System",
                IsRead = false
            };
            _context.Notifications.Add(notification);
            _context.SaveChanges();

            var retrieved = _context.Notifications.First();
            Assert.Equal("Student", retrieved.EntityType);
            Assert.Equal("Test notification", retrieved.Message);
        }

        public void Dispose()
        {
            _context?.Dispose();
        }
    }
}

